from collections import deque

class Solution(object):
    def jump(self, nums):
        n = len(nums)
        queue = deque([(0, 0)])  # (position, steps)
        visited = [0]*n
        visited[0] = 1

        while queue:
            pos, step = queue.popleft()
            if pos == n-1:
                return step  # Reach the end
            for i in range(1, nums[pos]+1):
                if pos+i < n and visited[pos+i] == 0:
                    queue.append((pos+i, step+1))
                    visited[pos+i] = 1

