class Solution(object):
    def toHex(self, num):
        if num == 0:
            return '0'
        mp = {10:'a', 11:'b', 12:'c', 13:'d', 14:'e', 15:'f'}
        hex_list = []
        for _ in range(8):
            n = num & 0xf
            if n >= 10:
                hex_list.append(mp[n])
            else:
                hex_list.append(str(n))
            num = num >> 4
        # remove leading zeroes
        while len(hex_list) > 1 and hex_list[-1] == '0':
            hex_list.pop()
        # reverse list to get correct order
