class Solution(object):
    def calculate(self, s):
        num, stack, sign, res = 0, [], '+', 0
        for i in range(len(s)):
            if s[i].isdigit():
                num = num*10 + int(s[i])
            if s[i] in "+-*/" or i == len(s)-1:
                if sign == '+':
                    stack.append(num)
                elif sign == '-':
                    stack.append(-num)
                elif sign == '*':
                    stack.append(stack.pop() * num)
                elif sign == '/':
                    # Python 3 division result is float, so we need to convert it to int.
                    stack.append(int(stack.pop() / float(num)))
                num = 0
                sign = s[i]
            if s[i] == '(':
                # push the result and sign before '(' into the stack, and start a new calculation
                stack.append(res)
                stack.append(sign)
                res = 0
                sign = '+'
            if s[i] == ')':
                # calculate the result before ')'
                res += sum(stack)
                stack = []
        return sum(stack)

