class Solution(object):
    def minSwapsCouples(self, row):
        N = len(row) // 2
        uf = {i:i for i in range(N)}

        def find(x):
            if uf[x] != x:
                uf[x] = find(uf[x])
            return uf[x]

        def union(x, y):
            uf[find(x)] = find(y)

        for i in range(0, len(row), 2):
            union(row[i] // 2, row[i + 1] // 2)

        return len(row) // 2 - sum(find(x) == x for x in uf.values())

