class Solution(object):
    def longestPalindrome(self, s):
        """
        :type s: str
        :rtype: int
        """
        # create a dictionary to count the occurrence of each character
        count = {}
        for char in s:
            if char in count:
                count[char] += 1
            else:
                count[char] = 1

        # iterate through the dictionary to find the longest palindrome
        longest = 0
        odd_count = 0
        for char in count:
            if count[char] % 2 == 0:  # if the count is even, it can be used as part of the palindrome
                longest += count[char]
            else:  # if the count is odd, use it as part of the palindrome, but subtract 1 from the total length
                longest += count[char] - 1
                odd_count = 1  # there's at least one odd count character

        return longest + odd_count

