import heapq

class Solution(object):
    def cutOffTree(self, forest):
        if not forest:
            return -1
        m, n = len(forest), len(forest[0])
        trees = []
        for i in range(m):
            for j in range(n):
                if forest[i][j] > 1:
                    trees.append((forest[i][j], i, j))
        trees.sort()
        directions = [(0, 1), (1, 0), (-1, 0), (0, -1)]
        heap = [(0, 0, 0)]
        visited = set([(0, 0)])
        res = 0
        for i in range(len(trees)):
            target = trees[i]
            step = 0
            while heap:
                k = len(heap)
                for _ in range(k):
                    h, x, y = heapq.heappop(heap)
                    if (x, y) == (target[1], target[2]):
                        res += step
                        heap = [(target[0], target[1], target[2])]
                        visited = set([(target[1], target[2])])
                        break
                    for dx, dy in directions:
                        nx, ny = x + dx, y + dy
                        if 0 <= nx < m and 0 <= ny < n and forest[nx][ny] != 0 and (nx, ny) not in visited:
                            heapq.heappush(heap, (forest[nx][ny], nx, ny))
                            visited.add((nx, ny))
                else:
                    continue
                break
            else:
                return -1
        return res

