    # Add word to Trie, and check if there is any word in Trie which can be extended to form a palindrome.
    def addWord(self, word, index):
        node = self.root
        for i, char in enumerate(reversed(word)):
            if self.isPalindrome(word, 0, len(word) - 1 - i):
                node.palindrome_word_indices.append(index)
            node = node.next[char]
        node.next['#'] = TrieNode()
        node.next['#'].palindrome_word_indices.append(index)
        node.index = index

    # Search word in Trie, and check if there is any word in Trie which can be extended to form a palindrome.
    def searchWord(self, word, index):
        results = []
        node = self.root
        for i, char in enumerate(word):
            # check if any word in Trie can be extended to form a palindrome
            if node.index >= 0 and node.index != index and self.isPalindrome(word, i, len(word) - 1):
                results.append([index, node.index])
            if not node.next.get(char):
                return results
            node = node.next[char]
        # check if current word can be extended to form a palindrome
        for j in node.palindrome_word_indices:
            if index == j:
                continue
            results.append([index, j])
        return results

    # Check if word[i:j] is a palindrome.
    def isPalindrome(self, word, i, j):
        while i < j:
            if word[i] != word[j]:
                return False
            i, j = i + 1, j - 1
        return True

