        if not nums:
            return -1

        # Find the smallest element's index
        low, high = 0, len(nums) - 1
        while low < high:
            mid = (low + high) // 2
            if nums[mid] > nums[high]:
                low = mid + 1
            else:
                high = mid

        # Perform binary search
        rot = low
        low, high = 0, len(nums) - 1
        while low <= high:
            mid = (low + high) // 2
            real_mid = (mid + rot) % len(nums)
            if nums[real_mid] == target:
                return real_mid
            if nums[real_mid] < target:
                low = mid + 1
            else:
                high = mid - 1

