class Solution(object):
    def maximalRectangle(self, matrix):
        if not matrix or not matrix[0]:
            return 0
        row, col = len(matrix), len(matrix[0])
        heights = [0]*col
        maxArea = 0
        for i in range(row):
            for j in range(col):
                # update the height of the histogram
                if matrix[i][j] == '1':
                    heights[j] += 1
                else:
                    heights[j] = 0
            # calculate the maximum area of the histogram
            maxArea = max(maxArea, self.largestRectangleArea(heights))
        return maxArea

    def largestRectangleArea(self, heights):
        heights = [0] + heights + [0]
        stack = []
        maxArea = 0
        for i in range(len(heights)):
            while stack and heights[i] < heights[stack[-1]]:
                h = heights[stack.pop()]
                maxArea = max(maxArea, h * (i - stack[-1] - 1))
            stack.append(i)
        return maxArea

