            # check the row
            for x in range(9):
                if bo[row][x] == num:
                    return False
            # check the column
            for x in range(9):
                if bo[x][col] == num:
                    return False
            # check the box
            start_row, start_col = row - row % 3, col - col % 3
            for i in range(3):
                for j in range(3):
                    if bo[i + start_row][j + start_col] == num:
                        return False
            return True

        def solve(bo):
            for i in range(9):
                for j in range(9):
                    if bo[i][j] == ".":
                        for num in "123456789":
                            if is_valid(bo, i, j, num):
                                bo[i][j] = num  # make tentative assignment
                                if solve(bo):  # continue to fill the rest
                                    return True
                                bo[i][j] = "."  # revert the assignment if not valid
                        return False  # trigger backtracking
