class Solution(object):
    def candy(self, ratings):
        """
        :type ratings: List[int]
        :rtype: int
        """
        n = len(ratings)
        left = [1]*n
        right = [1]*n

        # Scan from left to right, update left[i] to be the minimum of left[i] and left[i-1]+1 if ratings[i] > ratings[i-1]
        for i in range(1, n):
            if ratings[i] > ratings[i-1]:
                left[i] = left[i-1] + 1

        # Scan from right to left, update right[i] to be the maximum of right[i] and right[i+1]+1 if ratings[i] > ratings[i+1]
        for i in range(n-2, -1, -1):
            if ratings[i] > ratings[i+1]:
                right[i] = right[i+1] + 1

        # The total number of candies is the maximum of left[i] and right[i] for each child
        return sum(max(left[i], right[i]) for i in range(n))

