            for i in range(len(ocuppied_rows)):
                if ocuppied_rows[i] == pos or \
                    ocuppied_rows[i] - i == pos or \
                    ocuppied_rows[i] + i == pos:
                    return False
            return True

        def place_queen(n, ocuppied_rows, results):
            if len(ocuppied_rows) == n:
                results[0] += 1
                return
            for i in range(n):
